<?php declare(strict_types=1); namespace Database\Factories\FreshProduce; use App\Domains\FreshProduce\Models\FreshProduce; use Illuminate\Database\Eloquent\Factories\Factory; final class FreshProduceFactory extends Factory { protected $model = FreshProduce::class; public function definition(): array { return ['name' => $this->faker->words(2, true), 'sku' => strtoupper('FRESH-' . $this->faker->bothify('####')), 'category' => $this->faker->randomElement(['fruits', 'vegetables', 'greens', 'roots', 'berries']), 'price' => $this->faker->numberBetween(40000, 150000), 'quantity_grams' => $this->faker->randomElement([250, 500, 1000, 1500, 2000]), 'current_stock' => $this->faker->numberBetween(50, 200), 'harvest_date' => $this->faker->dateTimeBetween('-7 days'), 'freshness_guarantee_hours' => 48, 'rating' => $this->faker->randomFloat(1, 4.0, 5), 'review_count' => $this->faker->numberBetween(30, 200), 'status' => 'active', 'correlation_id' => \Illuminate\Support\Str::uuid()->toString(), 'tags' => ['fresh', 'produce'], 'meta' => []]; } public function premium(): self { return $this->state(['quantity_grams' => 2000, 'price' => $this->faker->numberBetween(100000, 150000)]); } public function budget(): self { return $this->state(['quantity_grams' => 250, 'price' => $this->faker->numberBetween(40000, 60000)]); } }
